const raw = $input.first().json.choices[0].message.content;

let cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

const startIdx = cleaned.indexOf('{');
const endIdx = cleaned.lastIndexOf('}');
if (startIdx === -1 || endIdx === -1) {
  throw new Error('No JSON found: ' + cleaned.substring(0, 200));
}
cleaned = cleaned.substring(startIdx, endIdx + 1);

let data;
try {
  data = JSON.parse(cleaned);
} catch(e) {
  cleaned = cleaned.replace(/"((?:[^"\\]|\\.)*)"/gs, (match, inner) => {
    const fixed = inner
      .replace(/\n/g, '\\n')
      .replace(/\r/g, '\\r')
      .replace(/\t/g, '\\t');
    return '"' + fixed + '"';
  });
  try {
    data = JSON.parse(cleaned);
  } catch(e2) {
    throw new Error('Parse failed: ' + e2.message + ' | Content: ' + cleaned.substring(0, 300));
  }
}

data.user_topic = $('🎬 Topic Input Form1').item.json['Video Topic / Idea'];
data.user_language = $('🎬 Topic Input Form1').item.json['Language'] || 'English';

return [{ json: data }];

const uploadResult = $input.first().json;
const directUrl = uploadResult?.secure_url ?? uploadResult?.url ?? '';
if (!directUrl) throw new Error('Cloudinary upload failed: ' + JSON.stringify(uploadResult));
return [{ json: { audioUrl: directUrl } }];

const musicList = [
  'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3',
  'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
  'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3',
  'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-4.mp3',
  'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-5.mp3'
];
const randomMusic = musicList[Math.floor(Math.random() * musicList.length)];
return [{ json: { musicUrl: randomMusic } }];

const allItems = $input.all();
let pexelsData = {};
let scriptData = {};
let audioUrlData = {};
let musicData = {};

for (const item of allItems) {
  const j = item.json;
  if (j.videos) {
    pexelsData = j;
  } else if (j.script) {
    scriptData = j;
  } else if (j.audioUrl) {
    audioUrlData = j;
  } else if (j.musicUrl) {
    musicData = j;
  }
}

const audioUrl = audioUrlData.audioUrl 
  || allItems.find(i => i.json.audioUrl)?.json.audioUrl 
  || '';

const musicUrl = musicData.musicUrl || 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3';
const videos = pexelsData.videos ?? [];
const videoClips = videos
  .slice(0, 5)
  .map(v => {
    const hdFile = v.video_files?.find(f => f.quality === 'hd' && f.width >= 1280)
      || v.video_files?.find(f => f.width >= 1280)
      || v.video_files?.[0];
    return hdFile ? hdFile.link : null;
  })
  .filter(Boolean);

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
return [{ json: { ...scriptData, videoClips, audioUrl, musicUrl, timestamp } }];

const data = $input.first().json;
const clips = data.videoClips;
if (!clips || clips.length === 0) return [{ json: { error: 'No video clips found' } }];

const validClips = clips.filter(url => url && url.includes('.mp4'));
const useClips = validClips.length > 0 ? validClips : clips;
const clipDuration = Math.floor(60 / useClips.length);
const totalDuration = clipDuration * useClips.length;

const shotstackClips = useClips.map((url, i) => ({
  asset: { type: 'video', src: url, trim: 0, volume: 0 },
  start: i * clipDuration,
  length: clipDuration,
  fit: 'cover',
  scale: 1
}));

const titleClip = {
  asset: {
    type: 'html',
    html: '<p>' + (data.title || 'Video') + '</p>',
    css: 'p { font-family: Arial; font-size: 36px; color: #ffffff; text-align: center; text-shadow: 2px 2px 8px #000000; font-weight: bold; }',
    width: 1280,
    height: 200
  },
  start: 0,
  length: 4,
  position: 'bottom',
  offset: { y: -0.1 }
};

const watermarkClip = {
  asset: {
    type: 'html',
    html: '<p></p>',
    css: 'p { font-family: Arial; font-size: 28px; color: #FFD700; font-weight: bold; text-shadow: 2px 2px 6px #000000; background: rgba(0,0,0,0.5); padding: 8px 16px; border-radius: 8px; white-space: nowrap; }',
    width: 500,
    height: 80
  },
  start: 0,
  length: totalDuration,
  position: 'bottomLeft',
  offset: { x: 0.02, y: 0.05 },
  opacity: 1
};

const musicUrl = data.musicUrl || 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3';
const audioUrl = data.audioUrl || '';

const tracks = [
  { clips: [watermarkClip] },
  { clips: [titleClip] },
  { clips: shotstackClips }
];

if (audioUrl && audioUrl.startsWith('https://')) {
  tracks.splice(2, 0, {
    clips: [{
      asset: {
        type: 'audio',
        src: audioUrl,
        volume: 1,
        effect: 'fadeIn'
      },
      start: 0,
      length: totalDuration
    }]
  });
}

const shotstackPayload = {
  timeline: {
    soundtrack: {
      src: musicUrl,
      effect: 'fadeIn',
      volume: audioUrl ? 0.15 : 0.8
    },
    background: '#000000',
    tracks: tracks
  },
  output: {
    format: 'mp4',
    resolution: 'hd',
    fps: 25,
    size: { width: 1920, height: 1080 }
  },
  merge: []
};

return [{ json: { ...data, shotstackPayload } }];

const responseData = $input.first().json;
const renderId = responseData?.response?.id ?? responseData?.id;
if (!renderId) throw new Error('Render ID not found: ' + JSON.stringify(responseData));
const allData = $('🎬 Topic Build Shotstack Payload1').item.json;
return [{ json: { ...allData, renderId } }];

const statusData = $input.first().json;
const prevData = $('🆔 Topic Extract Render ID1').item.json;

const videoUrl = 
  statusData?.response?.url ??
  statusData?.response?.data?.url ??
  statusData?.data?.url ??
  statusData?.url ??
  null;

if (!videoUrl) {
  throw new Error('Video URL not found. Response was: ' + JSON.stringify(statusData));
}

return [{
  json: {
    ...prevData,
    finalVideoUrl: videoUrl,
    renderStatus: statusData?.response?.status ?? 'done'
  }
}];

const uploadResult = $input.first().json;
const scriptData = $('🎞️ Topic Extract Final Video URL1').item.json;

const report = {
  status: 'SUCCESS ✅',
  videoId: uploadResult.id,
  youtubeUrl: `https://youtube.com/watch?v=${uploadResult.id}`,
  title: scriptData.title,
  user_topic: scriptData.user_topic,
  topic: scriptData.topic,
  video_prompt: scriptData.video_prompt,
  tags: scriptData.tags,
  shotstackRender: scriptData.finalVideoUrl,
  aiModel: 'Groq llama-3.3-70b-versatile',
  tts: 'VoiceRSS TTS',
  videoAssembly: 'Shotstack Cloud API',
  uploadedAt: new Date().toISOString()
};

console.log('✅ Topic Video Published!', JSON.stringify(report, null, 2));
return [{ json: report }];

const data = $('🎞️ Topic Extract Final Video URL1').item.json;

// Try portrait clips first, fall back to landscape with contain
const portraitClips = ($('📋 Short Extract Portrait URLs').item.json || {}).shortPortraitClips || [];
const landscapeClips = (data.videoClips || []).filter(url => url && url.includes('.mp4'));

// Use portrait if available, else landscape
const rawClips = portraitClips.length > 0 ? portraitClips : landscapeClips;
const useClips = rawClips.slice(0, 5); // max 5 clips

if (useClips.length === 0) return [{ json: { error: 'No video clips found for short' } }];

const clipDuration = Math.floor(56 / useClips.length);
const totalDuration = clipDuration * useClips.length;
const usingPortrait = portraitClips.length > 0;

const shotstackClips = useClips.map((url, i) => ({
  asset: { type: 'video', src: url, trim: 0, volume: 0 },
  start: i * clipDuration,
  length: clipDuration,
  fit: usingPortrait ? 'cover' : 'contain',  // portrait=cover, landscape=contain (no stretch)
  scale: 1
}));

const titleClip = {
  asset: {
    type: 'html',
    html: '<p>' + (data.title || 'Short Video') + '</p>',
    css: 'p { font-family: Arial; font-size: 40px; color: #ffffff; text-align: center; text-shadow: 2px 2px 8px #000000; font-weight: bold; padding: 0 20px; }',
    width: 1080,
    height: 200
  },
  start: 0,
  length: 5,
  position: 'bottom',
  offset: { y: -0.05 }
};

const musicUrl = data.musicUrl || 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3';
const audioUrl = data.audioUrl || '';

const tracks = [
  { clips: [titleClip] },
  { clips: shotstackClips }
];

if (audioUrl && audioUrl.startsWith('https://')) {
  tracks.splice(1, 0, {
    clips: [{
      asset: { type: 'audio', src: audioUrl, volume: 1, effect: 'fadeIn' },
      start: 0,
      length: totalDuration
    }]
  });
}

const shortPayload = {
  timeline: {
    soundtrack: { src: musicUrl, effect: 'fadeIn', volume: audioUrl ? 0.15 : 0.8 },
    background: '#000000',
    tracks: tracks
  },
  output: {
    format: 'mp4',
    resolution: 'hd',
    fps: 25,
    size: { width: 1080, height: 1920 }
  },
  merge: []
};

return [{ json: { ...data, shortPayload, shortTotalDuration: totalDuration, usingPortrait } }];

const response = $input.first().json;
const renderId = response.response?.id || response.id;
if (!renderId) throw new Error('Short render ID not found: ' + JSON.stringify(response));
return [{ json: { ...$('📱 Short Build Shotstack Payload').item.json, shortRenderId: renderId } }];

const response = $input.first().json;
const videoUrl = response.response?.url || response.url;
if (!videoUrl) throw new Error('Short video URL not found');
const baseData = $('🆔 Short Extract Render ID').item.json;
return [{ json: { ...baseData, shortFinalVideoUrl: videoUrl } }];

const uploadResult = $input.first().json;
const scriptData = $('🆔 Short Extract Render ID').item.json;

const report = {
  status: 'SHORT SUCCESS ✅',
  videoId: uploadResult.id,
  youtubeShortUrl: `https://youtube.com/shorts/${uploadResult.id}`,
  title: scriptData.title + ' #Shorts',
  shortRender: scriptData.shortFinalVideoUrl,
  uploadedAt: new Date().toISOString()
};

console.log('✅ Short Video Published!', JSON.stringify(report, null, 2));
return [{ json: report }];

const pexelsData = $input.first().json;
const videos = pexelsData.videos || [];
const videoUrls = [];

for (const video of videos) {
  const files = video.video_files || [];

  const portrait = files.find(f => f.quality === 'hd' && f.width && f.height && f.height > f.width);
  const sd = files.find(f => f.quality === 'sd' && f.width && f.height && f.height > f.width);
  const any = files.find(f => f.link && f.link.includes('.mp4'));

  const chosen = portrait || sd || any;
  if (chosen) videoUrls.push(chosen.link);
  if (videoUrls.length >= 6) break;
}

return [{ json: { shortPortraitClips: videoUrls } }];
